#include <bits/stdc++.h>
using namespace std;

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n;
    if (!(cin >> n)) return 0;
    vector<long long> a(n);
    for (int i = 0; i < n; ++i) cin >> a[i];
    long long xorAll = 0;
    for (auto v : a) xorAll ^= v;
    long long diffBit = xorAll & -xorAll; // rightmost set bit
    long long x = 0, y = 0;
    for (auto v : a) {
        if (v & diffBit) x ^= v; else y ^= v;
    }
    if (x > y) swap(x, y);
    cout << x << ' ' << y << '\n';
    return 0;
}

