import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    n = int(data[0])
    nums = list(map(int, data[1:1+n]))
    xor_all = 0
    for v in nums:
        xor_all ^= v
    diff_bit = xor_all & -xor_all
    x = y = 0
    for v in nums:
        if v & diff_bit:
            x ^= v
        else:
            y ^= v
    if x > y:
        x, y = y, x
    print(x, y)

if __name__ == "__main__":
    solve()

